def test_ach_transfer_above_limit_accepted_with_stepup(api_client, verified_ach_account, funded_account, valid_stepup_token):
    headers = {"X-Step-Up-Token": valid_stepup_token}
    payload = {
        "source_account_id": funded_account["id"],
        "destination_ach_account_id": verified_ach_account["id"],
        "amount": "15000.00",
        "currency": "USD"
    }
    resp = api_client.post("/transfers/ach", json=payload, headers=headers)
    assert resp.status_code == 202
    body = resp.json()
    assert body["status"] == "QUEUED"
    assert "transfer_id" in body
